        raise TypeError("Arguments must be integers")
    return a + b

# Magic methods examples
class Vector:
    """A simple 2D vector class demonstrating magic methods."""

    def __init__(self, x, y):
        self.x = x
        self.y = y

    # String representation
    def __str__(self):
        return f"Vector({self.x}, {self.y})"

    def __repr__(self):
        return f"Vector({self.x}, {self.y})"

    # Arithmetic operations
    def __add__(self, other):
        return Vector(self.x + other.x, self.y + other.y)

    def __sub__(self, other):
        return Vector(self.x - other.x, self.y - other.y)

    def __mul__(self, scalar):
        return Vector(self.x * scalar, self.y * scalar)

    def __rmul__(self, scalar):  # Reverse multiplication
        return self.__mul__(scalar)

    # Comparison operations
    def __eq__(self, other):
        return self.x == other.x and self.y == other.y

    def __lt__(self, other):
        return self.magnitude() < other.magnitude()

    # Other useful methods
    def __abs__(self):
        return self.magnitude()

    def __len__(self):
        return 2  # Always 2D

    def __getitem__(self, index):
        if index == 0:
            return self.x
        elif index == 1:
            return self.y
        else:
            raise IndexError("Vector index out of range")

    def __contains__(self, value):
        return value == self.x or value == self.y

    # Helper method
    def magnitude(self):
        return (self.x**2 + self.y**2) ** 0.5

# Using the Vector class
v1 = Vector(2, 3)
v2 = Vector(4, 5)

# String representation
print(str(v1))    # Vector(2, 3)
print(repr(v1))   # Vector(2, 3)

# Arithmetic
v3 = v1 + v2
print(v3)         # Vector(6, 8)

v4 = v2 - v1
print(v4)         # Vector(2, 2)

v5 = v1 * 3
print(v5)         # Vector(6, 9)

v6 = 3 * v1       # Uses __rmul__
print(v6)         # Vector(6, 9)

# Comparison
print(v1 == Vector(2, 3))  # True
print(v1 < v2)             # True (magnitude comparison)

# Other operations
print(abs(v1))             # 3.605... (magnitude)
print(len(v1))             # 2
print(v1[0])               # 2
print(2 in v1)             # True
print(5 in v1)             # False

# More magic methods examples
class Book:
    """Book class with more magic methods."""

    def __init__(self, title, author, pages):
        self.title = title
        self.author = author
        self.pages = pages

    # Called by len()
    def __len__(self):
        return self.pages

    # Called by bool() and in if statements
    def __bool__(self):
        return self.pages > 0

    # Called when object is called like a function
    def __call__(self):
        return f"{self.title} by {self.author}"

    # Context manager methods
    def __enter__(self):
        print(f"Opening {self.title}")
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        print(f"Closing {self.title}")
        return False

    # Attribute access
    def __getattr__(self, name):
        if name == "summary":
            return f"{self.title} ({self.pages} pages)"
        raise AttributeError(f"Book has no attribute {name}")

    def __setattr__(self, name, value):
        if name == "pages" and value < 0:
            raise ValueError("Pages cannot be negative")
        super().__setattr__(name, value)

    def __delattr__(self, name):
        if name == "title":
            raise AttributeError("Cannot delete title")
        super().__delattr__(name)

# Using Book class
book = Book("Python Guide", "John Doe", 300)

print(len(book))          # 300
print(bool(book))         # True
print(book())             # Python Guide by John Doe
print(book.summary)       # Python Guide (300 pages)

# Context manager
with book:
    print("Reading book...")

# Attribute management
book.pages = 350          # Works
# book.pages = -10        # ValueError: Pages cannot be negative
# del book.title          # AttributeError: Cannot delete title

# Iterator protocol
class Countdown:
    """Countdown iterator."""

    def __init__(self, start):
        self.current = start

    def __iter__(self):
        return self

    def __next__(self):
        if self.current <= 0:
            raise StopIteration
        value = self.current
        self.current -= 1
        return value

for num in Countdown(5):
    print(num, end=" ")  # 5 4 3 2 1

# Numeric type emulation
class Fraction:
    """Fraction class showing numeric magic methods."""

    def __init__(self, numerator, denominator):
        self.n = numerator
        self.d = denominator

    def __add__(self, other):
        return Fraction(self.n * other.d + other.n * self.d,
                        self.d * other.d)

    def __mul__(self, other):
        return Fraction(self.n * other.n, self.d * other.d)

    def __float__(self):
        return self.n / self.d

    def __int__(self):
        return int(float(self))

    def __str__(self):
        return f"{self.n}/{self.d}"

f1 = Fraction(1, 2)
f2 = Fraction(1, 3)
print(f"\n{f1} + {f2} = {f1 + f2}")  # 1/2 + 1/3 = 5/6
print(f"{f1} * {f2} = {f1 * f2}")  # 1/2 * 1/3 = 1/6

