# Classmethod and staticmethod decorators
class MyClass:
    class_var = "Class variable"

    def __init__(self, value):
        self.value = value

    @classmethod
    def from_string(cls, string):
        """Alternative constructor."""
        return cls(int(string))

    @staticmethod
