# Metaclass examples
# Basic metaclass
class MyMeta(type):
    """A simple metaclass that prints when class is created."""

    def __new__(cls, name, bases, attrs):
        print(f"MyMeta.__new__: Creating class {name}")
        # Add a class attribute
        attrs['created_by'] = 'MyMeta'
        return super().__new__(cls, name, bases, attrs)

    def __init__(self, name, bases, attrs):
        print(f"MyMeta.__init__: Initializing class {name}")
        super().__init__(name, bases, attrs)

# Using metaclass
class MyClass(metaclass=MyMeta):
    """A class with custom metaclass."""
    def __init__(self, value):
        self.value = value

print(f"\nMyClass attributes: {MyClass.created_by}")
obj = MyClass(10)
print(f"Object value: {obj.value}")

# Singleton metaclass
class SingletonMeta(type):
    """Metaclass for Singleton pattern."""
    _instances = {}

    def __call__(cls, *args, **kwargs):
        if cls not in cls._instances:
            cls._instances[cls] = super().__call__(*args, **kwargs)
        return cls._instances[cls]

class SingletonClass(metaclass=SingletonMeta):
    def __init__(self, value):
        self.value = value

    def __repr__(self):
        return f"SingletonClass({self.value})"

print("\nSingleton test:")
a = SingletonClass(1)
b = SingletonClass(2)  # Same instance
print(f"a is b: {a is b}")  # True
print(f"a.value: {a.value}")  # 1 (not 2!)
print(f"b.value: {b.value}")  # 1

# Metaclass for validation
class ValidateFieldsMeta(type):
    """Metaclass that validates class fields."""

    def __new__(cls, name, bases, attrs):
        # Check for required fields
        required_fields = attrs.get('required_fields', [])
        for field in required_fields:
            if field not in attrs:
                raise TypeError(f"{name} must define {field}")

        # Ensure methods start with lowercase
        for attr_name, attr_value in attrs.items():
            if callable(attr_value) and attr_name[0].isupper():
                raise TypeError(
                    f"Method {attr_name} in {name} must start with lowercase"
                )

        return super().__new__(cls, name, bases, attrs)

class ValidatedClass(metaclass=ValidateFieldsMeta):
    required_fields = ['required_method']

    def required_method(self):
        return "I'm required"

    def valid_method(self):  # OK - starts with lowercase
        return "Valid"

    # def InvalidMethod(self):  # Would raise error
    #     return "Invalid"

print("\nValidated class created successfully")

# Metaclass for registration
class PluginMeta(type):
    """Metaclass that registers plugins."""
    plugins = []

    def __new__(cls, name, bases, attrs):
        new_class = super().__new__(cls, name, bases, attrs)
        # Don't register base class
        if name != 'Plugin':
            cls.plugins.append(new_class)
        return new_class

class Plugin(metaclass=PluginMeta):
    """Base plugin class."""
    pass

class PluginA(Plugin):
    """Plugin A."""
    pass

class PluginB(Plugin):
    """Plugin B."""
    pass

print(f"\nRegistered plugins: {PluginMeta.plugins}")

# Metaclass for automatic property creation
class AutoPropertyMeta(type):
    """Metaclass that creates properties from get_/set_ methods."""

    def __new__(cls, name, bases, attrs):
        # Find getter/setter pairs
        properties = {}
        for attr_name, attr_value in attrs.items():
            if attr_name.startswith('get_'):
                prop_name = attr_name[4:]
                if f'set_{prop_name}' in attrs:
                    properties[prop_name] = (
                        attr_value,
                        attrs[f'set_{prop_name}']
                    )

        # Create properties
        for prop_name, (getter, setter) in properties.items():
            attrs[prop_name] = property(getter, setter)
            # Remove original methods
            del attrs[f'get_{prop_name}']
            del attrs[f'set_{prop_name}']

        return super().__new__(cls, name, bases, attrs)

class Person(metaclass=AutoPropertyMeta):
    def __init__(self, name):
        self._name = name

    def get_name(self):
        return self._name

    def set_name(self, value):
        if not value:
            raise ValueError("Name cannot be empty")
        self._name = value

print("\nAuto property test:")
