# Real-world example: ORM metaclass
class Field:
    """Database field descriptor."""
    def __init__(self, field_type):
        self.field_type = field_type
        self.name = None

    def __set_name__(self, owner, name):
        self.name = name

    def __get__(self, obj, objtype=None):
        if obj is None:
            return self
        return obj.__dict__.get(self.name)

    def __set__(self, obj, value):
        if not isinstance(value, self.field_type):
            raise TypeError(f"{self.name} must be {self.field_type}")
        obj.__dict__[self.name] = value

class ModelMeta(type):
    """ORM-like metaclass."""
    def __new__(cls, name, bases, attrs):
        # Collect fields
        fields = {}
        for attr_name, attr_value in attrs.items():
            if isinstance(attr_value, Field):
                fields[attr_name] = attr_value

        # Store fields in class
        attrs['_fields'] = fields

        # Add table name
        if '__tablename__' not in attrs:
            attrs['__tablename__'] = name.lower()

        return super().__new__(cls, name, bases, attrs)

class Model(metaclass=ModelMeta):
    """Base model class."""
    def __init__(self, **kwargs):
        for key, value in kwargs.items():
            setattr(self, key, value)

    def __repr__(self):
        fields = ', '.join(
            f"{name}={getattr(self, name)}"
            for name in self._fields
        )
        return f"{self.__class__.__name__}({fields})"

class User(Model):
    __tablename__ = "users"
    id = Field(int)
    name = Field(str)
    email = Field(str)

print("\nORM-like example:")
user = User(id=1, name="Alice", email="alice@example.com")
print(user)
print(f"Table name: {User.__tablename__}")
print(f"Fields: {User._fields}")

