# Basic magic methods
class Vector:
    """Demonstrates multiple magic methods."""

    def __init__(self, x, y):
        self.x = x
        self.y = y

    # String representation
    def __repr__(self):
        return f"Vector({self.x}, {self.y})"

    def __str__(self):
        return f"({self.x}, {self.y})"

    # Arithmetic operators
    def __add__(self, other):
        return Vector(self.x + other.x, self.y + other.y)

    def __sub__(self, other):
        return Vector(self.x - other.x, self.y - other.y)

    def __mul__(self, scalar):
        return Vector(self.x * scalar, self.y * scalar)

    def __rmul__(self, scalar):  # Right multiplication
        return self * scalar

    # Comparison operators
    def __eq__(self, other):
        return self.x == other.x and self.y == other.y

    def __lt__(self, other):
        # Compare by magnitude
        return (self.x**2 + self.y**2) < (other.x**2 + other.y**2)

    # Container methods
    def __len__(self):
        return 2  # Always 2D vector

    def __getitem__(self, index):
        if index == 0:
            return self.x
        elif index == 1:
            return self.y
        else:
            raise IndexError("Vector index out of range")

    def __setitem__(self, index, value):
        if index == 0:
            self.x = value
        elif index == 1:
            self.y = value
        else:
            raise IndexError("Vector index out of range")

    def __contains__(self, item):
        return item in (self.x, self.y)

    # Callable object
    def __call__(self, scalar):
        """Make vector callable to scale it."""
        return Vector(self.x * scalar, self.y * scalar)

    # Context manager methods
    def __enter__(self):
        print(f"Entering vector context: {self}")
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        print(f"Exiting vector context: {self}")
        return False

