        self.pages = pages
        self.current_page = 0

    # Attribute access
    def __getattr__(self, name):
        """Called when attribute not found."""
        if name == "description":
            return f"{self.title} by {self.author}"
        raise AttributeError(f"'{type(self).__name__}' object has no attribute '{name}'")

    def __setattr__(self, name, value):
        """Called when setting any attribute."""
        if name == "pages" and value < 0:
            raise ValueError("Pages cannot be negative")
        super().__setattr__(name, value)

    def __delattr__(self, name):
        """Called when deleting attribute."""
        if name in ["title", "author"]:
            raise AttributeError(f"Cannot delete {name}")
        super().__delattr__(name)

    # Numeric methods
    def __abs__(self):
        return abs(self.pages)

    def __bool__(self):
        return self.pages > 0

    # Iterator protocol
    def __iter__(self):
        self.current_page = 0
        return self

    def __next__(self):
        if self.current_page >= self.pages:
            raise StopIteration
        self.current_page += 1
        return f"Page {self.current_page}"

    # Right-hand operations
    def __radd__(self, other):
        return other + self.pages

